---
import MenuIcon from "lucide-static/icons/menu.svg"

import { Button } from "@/components/ui/button"
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible"
import { Header, HeaderActions } from "@/components/ui/header"
import { Icon } from "@/components/ui/icon"
import { Logo, LogoImage, LogoText } from "@/components/ui/logo"
import {
  NavigationMenu,
  NavigationMenuContent,
  NavigationMenuItem,
  NavigationMenuLink,
  NavigationMenuList,
  NavigationMenuTrigger,
  navigationMenuTriggerStyle,
} from "@/components/ui/navigation-menu"
import { Sheet, SheetContent, SheetTrigger } from "@/components/ui/sheet"
import {
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarMenuSub,
  SidebarMenuSubButton,
  SidebarMenuSubItem,
} from "@/components/ui/sidebar"
import { ThemeToggle } from "@/components/ui/theme-toggle"

interface Props {
  logo?: {
    src?: string
    alt?: string
    text?: string
    href?: string
  }
  links?: {
    icon?: string
    text?: string
    href?: string
    target?: string
  }[]
  socials?: string[]
  menus?: {
    text?: string
    href?: string
    links?: {
      text?: string
      href?: string
    }[]
  }[]
}

const { logo, menus, links, socials } = Astro.props

const desktopMenuItemClass = navigationMenuTriggerStyle({
  class: "h-8 bg-transparent px-3 py-0",
})
---

<Header>
  <Logo href={logo?.href || "/"}>
    <LogoImage src={logo?.src} alt={logo?.alt} />
    <LogoText>{logo?.text}</LogoText>
  </Logo>
  <NavigationMenu class="absolute left-1/2 -translate-x-1/2 max-lg:hidden">
    <NavigationMenuList class="flex list-none items-center gap-0">
      {
        menus?.map((menu, index) => (
          <NavigationMenuItem value={`menu-${index}`}>
            {menu.links && menu.links.length > 0 ? (
              <>
                <NavigationMenuTrigger class={desktopMenuItemClass}>
                  {menu.text}
                </NavigationMenuTrigger>
                <NavigationMenuContent>
                  <ul class="grid min-w-48 gap-1">
                    {menu.links?.map((link) => (
                      <li>
                        <NavigationMenuLink href={link.href} class="w-full">
                          {link.text}
                        </NavigationMenuLink>
                      </li>
                    ))}
                  </ul>
                </NavigationMenuContent>
              </>
            ) : (
              <NavigationMenuLink class={desktopMenuItemClass} href={menu.href}>
                {menu.text}
              </NavigationMenuLink>
            )}
          </NavigationMenuItem>
        ))
      }
    </NavigationMenuList>
  </NavigationMenu>
  <HeaderActions class="max-lg:hidden">
    <ThemeToggle />
    {
      socials?.map((social) => (
        <Button
          as="a"
          variant="ghost"
          size="icon-sm"
          href={social}
          target="_blank"
        >
          <Icon href={social} />
        </Button>
      ))
    }
    {
      links?.map(({ icon, text, ...link }, i) => (
        <Button
          variant={i === links.length - 1 ? "default" : "ghost"}
          size="sm"
          {...link}
        >
          {icon && <Icon name={icon} />}
          {text}
        </Button>
      ))
    }
  </HeaderActions>
  <Sheet>
    <SheetTrigger
      class="lg:hidden"
      variant="ghost"
      size="icon"
      name="open-menu-button"
    >
      <MenuIcon class="size-5" />
    </SheetTrigger>
    <SheetContent class="overflow-y-auto px-4 py-12">
      <SidebarMenu>
        {
          menus?.map((menu) => (
            <SidebarMenuItem>
              {menu.links && menu.links.length > 0 ? (
                <Collapsible>
                  <CollapsibleTrigger class="w-full border-0 bg-transparent p-0 text-left">
                    <SidebarMenuButton as="span">{menu.text}</SidebarMenuButton>
                  </CollapsibleTrigger>
                  <CollapsibleContent>
                    <SidebarMenuSub>
                      {menu.links?.map((link) => (
                        <SidebarMenuSubItem>
                          <SidebarMenuSubButton href={link.href}>
                            {link.text}
                          </SidebarMenuSubButton>
                        </SidebarMenuSubItem>
                      ))}
                    </SidebarMenuSub>
                  </CollapsibleContent>
                </Collapsible>
              ) : (
                <SidebarMenuButton
                  class="h-10 w-full rounded-md px-4 text-xl has-[>svg]:px-4"
                  href={menu.href}
                >
                  {menu.text}
                </SidebarMenuButton>
              )}
            </SidebarMenuItem>
          ))
        }
      </SidebarMenu>
      <HeaderActions>
        {
          links?.map(({ icon, text, ...link }, i) => (
            <Button
              variant={i === links.length - 1 ? "default" : "ghost"}
              {...link}
            >
              {icon && <Icon name={icon} />}
              {text}
            </Button>
          ))
        }
      </HeaderActions>
      <HeaderActions>
        {
          socials?.map((social) => (
            <Button as="a" variant="ghost" size="icon" href={social}>
              <Icon href={social} />
            </Button>
          ))
        }
      </HeaderActions>
    </SheetContent>
  </Sheet>
</Header>
